    string minWindow(string s, string t) {
        unordered_map<char, int> t_count;
        for (char c : t) t_count[c]++;
        int required = t_count.size();
        int left = 0, min_len = INT_MAX, min_str = "";
        unordered_map<char, int> window_count;
        for (int right = 0; right < s.size(); right++) {
            char c = s[right];
            if (t_count.find(c) != t_count.end()) {
                window_count[c]++;
                if (window_count[c] == t_count[c]) required--;
            }
            while (required == 0) {
                if (right - left + 1 < min_len) {
                    min_len = right - left + 1;
                    min_str = s.substr(left, min_len);
                }
                char d = s[left];
                if (t_count.find(d) != t_count.end()) {
                    if (window_count[d] == t_count[d]) required++;
                    window_count[d]--;
                }
                left++;
            }
        }
        return min_str;
    }
};```
